'use client'
import { useState } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import { PlusIcon, XMarkIcon, TagIcon, CurrencyDollarIcon, CubeIcon } from '@heroicons/react/24/outline'
import { useProductStore } from '@/store/useProductStore'

const CATEGORIES = [
  'Softdrinks',
  'Hard Drinks',
  'Junkfoods',
  'Noodles',
  'Canned Goods',
  'MSG',
  'Biscuits',
  'Candy',
  'Others'
]

export function AddProductModal() {
  const [isOpen, setIsOpen] = useState(false)
  const addProduct = useProductStore((state) => state.addProduct)
  
  const [formData, setFormData] = useState({
    name: '',
    category: '',
    price: '',
    stock: '',
    unit: 'pcs'
  })

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault()
    if (!formData.name || !formData.category || !formData.price || !formData.stock) {
      return
    }

    addProduct({
      name: formData.name,
      category: formData.category,
      price: parseFloat(formData.price),
      stock: parseInt(formData.stock),
      unit: formData.unit
    })

    setFormData({ name: '', category: '', price: '', stock: '', unit: 'pcs' })
    setIsOpen(false)
  }

  return (
    <>
      <button
        onClick={() => setIsOpen(true)}
        className="neumorphic-flat hover:neumorphic-pressed px-4 py-3 rounded-lg flex items-center gap-2 transition-all"
      >
        <PlusIcon className="size-4" />
        <span className="font-medium">Add Product</span>
      </button>

      <AnimatePresence>
        {isOpen && (
          <motion.div
            className="fixed inset-0 z-50 flex items-center justify-center bg-black/40"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={() => setIsOpen(false)}
          >
            <motion.div
              className="neumorphic p-6 w-full max-w-md"
              initial={{ scale: 0.95, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              exit={{ scale: 0.95, opacity: 0 }}
              onClick={(e) => e.stopPropagation()}
            >
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-lg font-semibold text-primary">Add New Product</h2>
                <button
                  onClick={() => setIsOpen(false)}
                  className="neumorphic-flat hover:neumorphic-pressed p-2 rounded-lg transition-all"
                >
                  <XMarkIcon className="size-4" />
                </button>
              </div>

              <form onSubmit={handleSubmit} className="space-y-4">
                <div>
                  <label className="block text-sm font-medium text-secondary mb-2">Product Name</label>
                  <div className="relative">
                    <TagIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 size-4 text-secondary" />
                    <input
                      type="text"
                      value={formData.name}
                      onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                      className="w-full neumorphic-inset pl-10 pr-4 py-3 rounded-lg focus:outline-none"
                      placeholder="Enter product name"
                      required
                    />
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-secondary mb-2">Category</label>
                  <select
                    value={formData.category}
                    onChange={(e) => setFormData({ ...formData, category: e.target.value })}
                    className="w-full neumorphic-inset px-4 py-3 rounded-lg focus:outline-none"
                    required
                  >
                    <option value="">Select category</option>
                    {CATEGORIES.map((category) => (
                      <option key={category} value={category}>
                        {category}
                      </option>
                    ))}
                  </select>
                </div>

                <div className="grid grid-cols-2 gap-4">
                  <div>
                    <label className="block text-sm font-medium text-secondary mb-2">Price</label>
                    <div className="relative">
                      <CurrencyDollarIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 size-4 text-secondary" />
                      <input
                        type="number"
                        step="0.01"
                        min="0"
                        value={formData.price}
                        onChange={(e) => setFormData({ ...formData, price: e.target.value })}
                        className="w-full neumorphic-inset pl-10 pr-4 py-3 rounded-lg focus:outline-none"
                        placeholder="0.00"
                        required
                      />
                    </div>
                  </div>

                  <div>
                    <label className="block text-sm font-medium text-secondary mb-2">Stock</label>
                    <div className="relative">
                      <CubeIcon className="absolute left-3 top-1/2 transform -translate-y-1/2 size-4 text-secondary" />
                      <input
                        type="number"
                        min="0"
                        value={formData.stock}
                        onChange={(e) => setFormData({ ...formData, stock: e.target.value })}
                        className="w-full neumorphic-inset pl-10 pr-4 py-3 rounded-lg focus:outline-none"
                        placeholder="0"
                        required
                      />
                    </div>
                  </div>
                </div>

                <div>
                  <label className="block text-sm font-medium text-secondary mb-2">Unit</label>
                  <select
                    value={formData.unit}
                    onChange={(e) => setFormData({ ...formData, unit: e.target.value })}
                    className="w-full neumorphic-inset px-4 py-3 rounded-lg focus:outline-none"
                  >
                    <option value="pcs">Pieces (pcs)</option>
                    <option value="pack">Pack</option>
                    <option value="bottle">Bottle</option>
                    <option value="can">Can</option>
                    <option value="box">Box</option>
                  </select>
                </div>

                <div className="flex gap-3 pt-4">
                  <button
                    type="button"
                    onClick={() => setIsOpen(false)}
                    className="flex-1 neumorphic-flat hover:neumorphic-pressed py-3 rounded-lg transition-all"
                  >
                    Cancel
                  </button>
                  <button
                    type="submit"
                    className="flex-1 bg-accent text-white py-3 rounded-lg hover:bg-blue-600 transition-all"
                  >
                    Save Product
                  </button>
                </div>
              </form>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  )
}