'use client'
import { ProductCard } from '@/components/pos/ProductCard'
import { CartSidebar } from '@/components/pos/CartSidebar'
import { AddProductModal } from '@/components/products/AddProductModal'
import { useProductStore } from '@/store/useProductStore'

export default function POSPage() {
  const products = useProductStore((state) => state.products)

  return (
    <div className="grid grid-cols-1 lg:grid-cols-[1fr_380px] gap-6 p-6">
      <div className="space-y-6">
        <div className="flex items-center justify-between">
          <h1 className="text-2xl font-bold text-primary">POS Terminal</h1>
          <AddProductModal />
        </div>
        
        <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
          {products.length > 0 ? (
            products.map((product) => (
              <ProductCard
                key={product.id}
                id={product.id}
                name={product.name}
                price={product.price}
                category={product.category}
                stock={product.stock}
              />
            ))
          ) : (
            <div className="neumorphic p-6 text-center text-secondary col-span-full">
              No products available. Click "Add Product" to create your first product.
            </div>
          )}
        </div>
      </div>
      <div>
        <CartSidebar />
      </div>
    </div>
  )
}