'use client'
import { PlusIcon } from '@heroicons/react/24/outline'
import { useCart } from '@/store/cart'

interface ProductCardProps {
  id: string
  name: string
  price: number
  category: string
  stock: number
}

export function ProductCard({ id, name, price, category, stock }: ProductCardProps) {
  const add = useCart(s => s.add)
  
  const isLowStock = stock <= 5

  return (
    <div className="neumorphic p-6 flex flex-col gap-4 hover:neumorphic-flat transition-all">
      <div className="flex-1">
        <div className="text-lg font-semibold text-primary">{name}</div>
        <div className="text-sm text-secondary mb-1">{category}</div>
        <div className="text-secondary">${price.toFixed(2)}</div>
        <div className={`text-xs mt-2 ${
          isLowStock ? 'text-red-500' : 'text-secondary'
        }`}>
          Stock: {stock} pcs
        </div>
      </div>
      
      <button 
        onClick={() => add({ id, name, price })} 
        disabled={stock === 0}
        className={`mt-auto px-4 py-3 rounded-lg flex items-center gap-2 transition-all ${
          stock > 0
            ? 'neumorphic-flat hover:neumorphic-pressed'
            : 'neumorphic-inset text-muted cursor-not-allowed'
        }`}
      >
        <PlusIcon className="size-4" />
        <span className="font-medium">{stock > 0 ? 'Quick Add' : 'Out of Stock'}</span>
      </button>
    </div>
  )
}